Q00352:
SELECT
  CAST(SUM(IIF(T1.language = 'Chinese Simplified', 1, 0)) AS REAL) * 100 / COUNT(T1.id)
FROM foreign_data AS T1;

Q00368:
SELECT
  CAST(SUM(CASE WHEN T1.borderColor = 'borderless' THEN 1 ELSE 0 END) AS REAL) * 100 / COUNT(T1.id)
FROM cards AS T1;

Q00402:
SELECT
  CAST(SUM(CASE WHEN T1.isStorySpotlight = 1 AND T1.isTextless = 0 THEN 1 ELSE 0 END) AS REAL) * 100 / COUNT(T1.id)
FROM cards AS T1;

Q00424:
SELECT
  SUM(CASE WHEN T1.isTextless = 1 AND T1.layout = 'normal' THEN 1 ELSE 0 END) * 100.0 / COUNT(T1.id)
FROM cards AS T1;

Q00571:
SELECT
  CAST(
    (SELECT COUNT(Id) FROM posts WHERE OwnerUserId = 24) AS REAL
  ) / (
    SELECT COUNT(Id) FROM votes WHERE UserId = 24
  );

Q01484:
SELECT
  SUM(CASE WHEN Country = 'CZE' AND Segment = 'Discount' THEN 1 ELSE 0 END) - SUM(CASE WHEN Country = 'SVK' AND Segment = 'Discount' THEN 1 ELSE 0 END)
FROM gasstations;

Q00117:
SELECT
  CAST(SUM(CASE WHEN T1.status = 'A' THEN T1.amount ELSE 0 END) AS REAL) * 100 / SUM(T1.amount)
FROM loan AS T1;

Q01346:
SELECT phone
FROM member
WHERE first_name = 'Carlo' AND last_name = 'Jacobs';

Q01152:
SELECT CAST(SUM(CASE WHEN Admission = '+' THEN 1 ELSE 0 END) AS REAL) / SUM(CASE WHEN Admission = '-' THEN 1 ELSE 0 END)
FROM Patient
WHERE Diagnosis = 'SLE';

Q00227:
SELECT
  ROUND(
    CAST(SUM(CASE WHEN label = '+' THEN 1 ELSE 0 END) AS REAL) * 100.0 / COUNT(molecule_id),
    3
  )
FROM molecule;
